const API_URL = "http://localhost:5000/api";

// Función auxiliar para obtener el token del localStorage
const getAuthHeaders = () => {
    const savedUser = localStorage.getItem('user-session');
    if (savedUser) {
        const { token } = JSON.parse(savedUser);
        return {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}` // <--- AQUÍ ESTÁ LA LLAVE MAESTRA
        };
    }
    return { 'Content-Type': 'application/json' };
};

export const api = {
    // --- AUTH ---
    login: async (email, password) => {
        const response = await fetch(`${API_URL}/auth/login`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ correo: email, password: password })
        });
        if (!response.ok) throw new Error("Credenciales inválidas");
        return await response.json();
    },

    // --- LOCALES ---
    getLocalesVendedor: async (vendedorId) => {
        const res = await fetch(`${API_URL}/locales/vendedor/${vendedorId}`, {
            headers: getAuthHeaders() // Agregamos headers con token
        });
        return await res.json();
    },
    crearLocal: async (data) => {
        const res = await fetch(`${API_URL}/locales`, {
            method: 'POST',
            headers: getAuthHeaders(),
            body: JSON.stringify(data)
        });
        return await res.json();
    },
    actualizarLocal: async (id, data) => {
        const res = await fetch(`${API_URL}/locales/${id}`, {
            method: 'PUT',
            headers: getAuthHeaders(),
            body: JSON.stringify(data)
        });
        return await res.json();
    },
    eliminarLocal: async (id) => {
        return await fetch(`${API_URL}/locales/${id}`, { 
            method: 'DELETE',
            headers: getAuthHeaders()
        });
    },

    // --- OFERTAS ---
    // Nota: Para ofertas usamos headers especiales porque enviamos archivos (FormData)
    getOfertasLocal: async (localId) => {
        const res = await fetch(`${API_URL}/ofertas/local/${localId}`, {
            headers: getAuthHeaders()
        });
        return await res.json();
    },
    crearOferta: async (formData) => {
        const savedUser = localStorage.getItem('user-session');
        const token = savedUser ? JSON.parse(savedUser).token : '';
        
        const res = await fetch(`${API_URL}/ofertas`, {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${token}` }, // NO enviar Content-Type en FormData
            body: formData 
        });
        return await res.json();
    },
    // ... aplicar lo mismo para actualizarOferta y eliminarOferta
};
